edits.new_string:
# Strip a single trailing CR/LF or LF, but leave CR/LF inside quoted
# fields untouched.
if line.endswith("\r\n"):
    line = line[:-2]
elif line.endswith("\n"):
    line = line[:-1]

fields: list[str] = []
field = ""
i = 0
n = len(line)
while i <= n:
    if i == n:
        ch = ","
    else:
        ch = line[i]

    if ch == '"':
        # Start of a quoted field.
        i += 1
        while i < n:
            ch = line[i]
            if ch == '"':
                if i + 1 < n and line[i + 1] == '"':
                    # Doubled quote -> literal quote.
                    field += '"'
                    i += 2
                else:
                    # End of quoted field.
                    i += 1
                    break
            else:
                field += ch
                i += 1
        # Append the field and skip a following comma if present.
        fields.append(field)
        field = ""
        if i < n and line[i] == ",":
            i += 1
    elif ch == ",":
        # End of a field.
        fields.append(field)
        field = ""
        i += 1
    else:
        field += ch
        i += 1

return fields

